function getSlope(x1: number, y1: number, x2: number, y2: number): string {
    const dx = x2 - x1;
    const dy = y2 - y1;
    if (dx === 0) return 'v'; // vertical line
    if (dy === 0) return 'h'; // horizontal line
    const gcdVal = gcd(dx, dy);
    const reducedDx = dx / gcdVal;
    const reducedDy = dy / gcdVal;
    return `${reducedDx}/${reducedDy}`;
}

function gcd(a: number, b: number): number {
    a = Math.abs(a);
    b = Math.abs(b);
    while (b) {
        [a, b] = [b, a % b];
    }
    return a;
}
