function solve(points: number[][]): number {
    const n = points.length;
    let T = 0;
    let B = 0;

    const gcd = (a: number, b: number): number => {
        a = Math.abs(a);
        b = Math.abs(b);
        if (b === 0) return a;
        return gcd(b, a % b);
    };

    const reduceFraction = (dx: number, dy: number): [number, number] => {
        if (dx === 0 && dy === 0) {
            return [0, 0];
        }
        if (dx === 0) {
            return [0, 1];
        }
        if (dy === 0) {
            return [1, 0];
        }
        let g = gcd(dx, dy);
        dx = dx / g;
        dy = dy / g;
        if (dx < 0) {
            dx = -dx;
            dy = -dy;
        }
        return [dx, dy];
    };

    const slopeGroup = new Map<string, [number, number][]>();
    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            const dx = points[j][0] - points[i][0];
            const dy = points[j][1] - points[i][1];
            const [rx, ry] = reduceFraction(dx, dy);
            const key = `${rx},${ry}`;
            if (!slopeGroup.has(key)) {
                slopeGroup.set(key, []);
            }
            slopeGroup.get(key)!.push([i, j]);
        }
    }

    for (const list of slopeGroup.values()) {
        const m = list.length;
        if (m < 2) continue;
        const deg: Record<number, number> = {};
        for (const [i, j] of list) {
            deg[i] = (deg[i] || 0) + 1;
            deg[j] = (deg[j] || 0) + 1;
        }
        let overlapPairs = 0;
        for (const vertex in deg) {
            const d = deg[vertex];
            overlapPairs += d * (d - 1) / 2;
        }
        T += (m * (m - 1) / 2 - overlapPairs);
    }

    const midGroup = new Map<string, [number, number][]>();
    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            const midX = points[i][0] + points[j][0];
            const midY = points[i][1] + points[j][1];
            const key = `${midX},${midY}`;
            if (!midGroup.has(key)) {
                midGroup.set(key, []);
            }
            midGroup.get(key)!.push([i, j]);
        }
    }

    for (const list of midGroup.values()) {
        const m = list.length;
        if (m < 2) continue;
        const slopeCount = new Map<string, number>();
        for (const [i, j] of list) {
            const dx = points[j][0] - points[i][0];
            const dy = points[j][1] - points[i][1];
            const [rx, ry] = reduceFraction(dx, dy);
            const slopeKey = `${rx},${ry}`;
            slopeCount.set(slopeKey, (slopeCount.get(slopeKey) || 0) + 1);
        }
        let sameSlopePairs = 0;
        for (const count of slopeCount.values()) {
            sameSlopePairs += count * (count - 1) / 2;
        }
        B += (m * (m - 1) / 2 - sameSlopePairs);
    }

    return T - B;
}
